import{_ as t,c as n,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Benutzerhandbuch: Kredite abfragen | opencode-mystatus","description":"Lernen Sie opencode-mystatus: Slash-Befehl oder natürliche Sprache für KI-Kredite.","frontmatter":{"title":"Benutzerhandbuch: Kredite abfragen | opencode-mystatus","sidebarTitle":"mystatus verwenden","subtitle":"Benutzerhandbuch: Kredite abfragen | opencode-mystatus","description":"Lernen Sie opencode-mystatus: Slash-Befehl oder natürliche Sprache für KI-Kredite.","tags":["Schnellstart","Slash-Befehl","Natürliche Sprache"],"prerequisite":["start-quick-start"],"order":2},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/start/using-mystatus/index.md","filePath":"de/vbgate/opencode-mystatus/start/using-mystatus/index.md"}'),s={name:"de/vbgate/opencode-mystatus/start/using-mystatus/index.md"};function r(o,e,l,h,d,u){return i(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="mystatus-verwenden-slash-befehl-und-naturliche-sprache" tabindex="-1">mystatus verwenden: Slash-Befehl und natürliche Sprache <a class="header-anchor" href="#mystatus-verwenden-slash-befehl-und-naturliche-sprache" aria-label="Permalink to &quot;mystatus verwenden: Slash-Befehl und natürliche Sprache&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Verwenden Sie den Slash-Befehl <code>/mystatus</code>, um Kredite aller KI-Plattformen mit einem Klick abzufragen</li><li>Verwenden Sie Fragen in natürlicher Sprache, damit OpenCode automatisch das mystatus-Tool aufruft</li><li>Verstehen Sie den Unterschied zwischen den beiden Auslösemethoden (Slash-Befehl und natürliche Sprache) und deren Anwendungsfälle</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Sie verwenden mehrere KI-Plattformen zur Entwicklung (OpenAI, Zhipu AI, GitHub Copilot usw.) und möchten wissen, wie viele Kredite auf jeder Plattform noch verbleiben, aber Sie möchten sich nicht separat auf jeder Plattform anmelden - das ist zu umständlich.</p><h2 id="wann-sollten-sie-dies-verwenden" tabindex="-1">Wann sollten Sie dies verwenden? <a class="header-anchor" href="#wann-sollten-sie-dies-verwenden" aria-label="Permalink to &quot;Wann sollten Sie dies verwenden?&quot;">​</a></h2><ul><li><strong>Wenn Sie schnell alle Plattformkredite anzeigen möchten</strong>: Überprüfen Sie dies vor der täglichen Entwicklung, um die Verwendung angemessen zu planen</li><li><strong>Wenn Sie wissen möchten, wie viel Kredit eine bestimmte Plattform hat</strong>: Zum Beispiel, um zu bestätigen, ob OpenAI bald aufgebraucht ist</li><li><strong>Wenn Sie überprüfen möchten, ob die Konfiguration wirksam ist</strong>: Nach der Konfiguration eines neuen Kontos überprüfen, ob die Abfrage normal funktioniert</li></ul><div class="info custom-block"><p class="custom-block-title">Vorabprüfung</p><p>Dieses Tutorial setzt voraus, dass Sie bereits die<a href="/docs/opencodedocs/de/vbgate/opencode-mystatus/start/quick-start/">opencode-mystatus-Plugin-Installation</a> abgeschlossen haben. Wenn Sie noch nicht installiert haben, schließen Sie bitte die Installationsschritte ab.</p></div><h2 id="grundlegende-idee" tabindex="-1">Grundlegende Idee <a class="header-anchor" href="#grundlegende-idee" aria-label="Permalink to &quot;Grundlegende Idee&quot;">​</a></h2><p>opencode-mystatus bietet zwei Methoden, um das mystatus-Tool auszulösen:</p><ol><li><strong>Slash-Befehl <code>/mystatus</code></strong>: Schnell, direkt, ohne Mehrdeutigkeit, geeignet für häufige Abfragen</li><li><strong>Natürliche Sprache</strong>: Flexibler, geeignet für abfragespezifische Szenarien</li></ol><p>Beide Methoden rufen dasselbe <code>mystatus</code>-Tool auf. Das Tool fragt alle konfigurierten KI-Plattformkredite parallel ab und gibt Ergebnisse mit Fortschrittsbalken, Nutzungsstatistiken und Rücksetz-Countdown zurück.</p><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-kreditabfrage-mit-slash-befehl" tabindex="-1">Schritt 1: Kreditabfrage mit Slash-Befehl <a class="header-anchor" href="#schritt-1-kreditabfrage-mit-slash-befehl" aria-label="Permalink to &quot;Schritt 1: Kreditabfrage mit Slash-Befehl&quot;">​</a></h3><p>Geben Sie in OpenCode den folgenden Befehl ein:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>Warum</strong> Der Slash-Befehl ist ein Schnellbefehlsmechanismus von OpenCode, um vordefinierte Tools schnell aufzurufen. Der Befehl <code>/mystatus</code> ruft direkt das mystatus-Tool auf, ohne zusätzliche Parameter.</p><p><strong>Was Sie sehen sollten</strong>: OpenCode gibt die Kreditinformationen aller konfigurierten Plattformen zurück (abhängig davon, welche Plattformen Sie konfiguriert haben).</p><h3 id="schritt-2-fragen-in-naturlicher-sprache" tabindex="-1">Schritt 2: Fragen in natürlicher Sprache <a class="header-anchor" href="#schritt-2-fragen-in-naturlicher-sprache" aria-label="Permalink to &quot;Schritt 2: Fragen in natürlicher Sprache&quot;">​</a></h3><p>Neben dem Slash-Befehl können Sie auch Fragen in natürlicher Sprache stellen. OpenCode erkennt Ihre Absicht automatisch und ruft das mystatus-Tool auf.</p><p>Probieren Sie diese Fragestellungen:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenAI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span></span></code></pre></div><p>oder</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">How</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> much</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> have</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> left?</span></span></code></pre></div><p>oder</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p><strong>Warum</strong> Abfragen in natürlicher Sprache entsprechen eher den alltäglichen Gesprächsgewohnheiten und eignen sich für Fragen in konkreten Entwicklungsszenarien. OpenCode erkennt durch semantische Übereinstimmung, dass Sie Kreditnutzung abfragen möchten, und ruft automatisch das mystatus-Tool auf.</p><p><strong>Was Sie sehen sollten</strong>: Das gleiche Ausgabeergebnis wie beim Slash-Befehl, nur die Auslösemethode ist unterschiedlich.</p><h3 id="schritt-3-konfiguration-des-slash-befehls-verstehen" tabindex="-1">Schritt 3: Konfiguration des Slash-Befehls verstehen <a class="header-anchor" href="#schritt-3-konfiguration-des-slash-befehls-verstehen" aria-label="Permalink to &quot;Schritt 3: Konfiguration des Slash-Befehls verstehen&quot;">​</a></h3><p>Wie funktioniert der Slash-Befehl <code>/mystatus</code>? Er ist in der OpenCode-Konfigurationsdatei definiert.</p><p>Öffnen Sie <code>~/.config/opencode/opencode.json</code> und suchen Sie den <code>command</code>-Teil:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opencode-mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Query quota usage for all AI accounts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;template&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Use the mystatus tool to query quota usage. Return the result as-is without modification.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Erklärung der wichtigsten Konfigurationselemente</strong>:</p><table tabindex="0"><thead><tr><th>Konfigurationselement</th><th>Wert</th><th>Funktion</th></tr></thead><tbody><tr><td><code>description</code></td><td>&quot;Query quota usage for all AI accounts&quot;</td><td>In der Befehlsliste angezeigte Beschreibung</td></tr><tr><td><code>template</code></td><td>&quot;Use to mystatus tool...&quot;</td><td>Weist OpenCode an, wie dieser Befehl zu verarbeiten ist</td></tr></tbody></table><p><strong>Warum ist ein template erforderlich</strong> Das template ist eine &quot;Anweisung&quot; an OpenCode: Wenn der Benutzer <code>/mystatus</code> eingibt, soll das mystatus-Tool aufgerufen werden und das Ergebnis unverändert an den Benutzer zurückgegeben werden (ohne Änderungen).</p><h2 id="kontrollpunkt-✅" tabindex="-1">Kontrollpunkt ✅ <a class="header-anchor" href="#kontrollpunkt-✅" aria-label="Permalink to &quot;Kontrollpunkt ✅&quot;">​</a></h2><p>Vergewissern Sie sich, dass Sie beide Verwendungsmethoden beherrschen:</p><table tabindex="0"><thead><tr><th>Fertigkeit</th><th>Überprüfungsmethode</th><th>Erwartetes Ergebnis</th></tr></thead><tbody><tr><td>Slash-Befehl-Abfrage</td><td><code>/mystatus</code> eingeben</td><td>Zeigt Kreditinformationen aller Plattformen</td></tr><tr><td>Abfrage in natürlicher Sprache</td><td>&quot;Check my OpenAI quota&quot; eingeben</td><td>Zeigt Kreditinformationen</td></tr><tr><td>Konfiguration verstehen</td><td>opencode.json aufrufen</td><td>Finden Sie die mystatus-Befehlskonfiguration</td></tr></tbody></table><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="haufiger-fehler-1-slash-befehl-reagiert-nicht" tabindex="-1">Häufiger Fehler 1: Slash-Befehl reagiert nicht <a class="header-anchor" href="#haufiger-fehler-1-slash-befehl-reagiert-nicht" aria-label="Permalink to &quot;Häufiger Fehler 1: Slash-Befehl reagiert nicht&quot;">​</a></h3><p><strong>Symptom</strong>: Nach Eingabe von <code>/mystatus</code> gibt es keine Reaktion</p><p><strong>Ursache</strong>: Die OpenCode-Konfigurationsdatei hat den Slash-Befehl nicht korrekt konfiguriert</p><p><strong>Lösung</strong>:</p><ol><li>Öffnen Sie <code>~/.config/opencode/opencode.json</code></li><li>Stellen Sie sicher, dass der <code>command</code>-Teil die <code>mystatus</code>-Konfiguration enthält (siehe Schritt 3)</li><li>Starten Sie OpenCode neu</li></ol><h3 id="haufiger-fehler-2-fragen-in-naturlicher-sprache-losen-mystatus-tool-nicht-aus" tabindex="-1">Häufiger Fehler 2: Fragen in natürlicher Sprache lösen mystatus-Tool nicht aus <a class="header-anchor" href="#haufiger-fehler-2-fragen-in-naturlicher-sprache-losen-mystatus-tool-nicht-aus" aria-label="Permalink to &quot;Häufiger Fehler 2: Fragen in natürlicher Sprache lösen mystatus-Tool nicht aus&quot;">​</a></h3><p><strong>Symptom</strong>: Nach Eingabe von &quot;Check my OpenAI quota&quot; ruft OpenCode das mystatus-Tool nicht auf, sondern versucht selbst zu antworten</p><p><strong>Ursache</strong>: OpenCode erkennt Ihre Absicht nicht korrekt</p><p><strong>Lösung</strong>:</p><ol><li>Versuchen Sie eine klarere Formulierung: &quot;Use mystatus tool to check my OpenAI quota&quot;</li><li>Oder verwenden Sie direkt den Slash-Befehl <code>/mystatus</code>, zuverlässiger</li></ol><h3 id="haufiger-fehler-3-anzeige-keine-konfigurierten-konten-gefunden" tabindex="-1">Häufiger Fehler 3: Anzeige &quot;Keine konfigurierten Konten gefunden&quot; <a class="header-anchor" href="#haufiger-fehler-3-anzeige-keine-konfigurierten-konten-gefunden" aria-label="Permalink to &quot;Häufiger Fehler 3: Anzeige &quot;Keine konfigurierten Konten gefunden&quot;&quot;">​</a></h3><p><strong>Symptom</strong>: Nach Ausführung von <code>/mystatus</code> wird &quot;Keine konfigurierten Konten gefunden&quot; angezeigt</p><p><strong>Ursache</strong>: Es wurden keine Authentifizierungsinformationen für eine Plattform konfiguriert</p><p><strong>Lösung</strong>:</p><ul><li>Mindestens Authentifizierungsinformationen für eine Plattform konfigurieren (OpenAI, Zhipu AI, Z.ai, GitHub Copilot oder Google Cloud)</li><li>Siehe <a href="/docs/opencodedocs/de/vbgate/opencode-mystatus/start/quick-start/">Schnellstart-Tutorial</a> für Konfigurationsdetails</li></ul><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Das mystatus-Tool bietet zwei Verwendungsmöglichkeiten:</p><ol><li><strong>Slash-Befehl <code>/mystatus</code></strong>: Schnell und direkt, geeignet für häufige Abfragen</li><li><strong>Fragen in natürlicher Sprache</strong>: Flexibler, geeignet für spezifische Szenarien</li></ol><p>Beide Methoden fragen alle konfigurierten KI-Plattformkredite parallel ab und geben Ergebnisse mit Fortschrittsbalken und Rücksetz-Countdown zurück. Die Slash-Befehlskonfiguration wird in <code>~/.config/opencode/opencode.json</code> definiert und weist durch template OpenCode an, wie das mystatus-Tool aufgerufen wird.</p><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="/docs/opencodedocs/de/vbgate/opencode-mystatus/start/understanding-output/">Ausgabe verstehen: Fortschrittsbalken, Rücksetzzeit und mehrere Konten</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie Sie die Bedeutung von Fortschrittsbalken interpretieren</li><li>Wie Rücksetzzeit-Countdown berechnet wird</li><li>Ausgabeformat bei mehreren Konten</li><li>Funktionsweise der Fortschrittsbalkenerzeugung</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Toolbeschreibung</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>30-31</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Parallele Abfrage aller Plattformen</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>49-56</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>: Keine (dieser Abschnitt führt hauptsächlich Aufrufmethoden ein, keine spezifischen Konstanten)</p><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>mystatus()</code>: Hauptfunktion des mystatus-Tools, liest die Authentifizierungsdatei und fragt alle Plattformen parallel ab (<code>plugin/mystatus.ts:29-33</code>)</li><li><code>collectResult()</code>: Sammelt Abfrageergebnisse in Arrays results und errors (<code>plugin/mystatus.ts:100-116</code>)</li></ul></details>`,63)])])}const p=t(s,[["render",r]]);export{g as __pageData,p as default};
